// Build the Anthropic messages array from incoming request
const body = $input.first().json.body ?? $input.first().json;

const userText   = body.message   ?? '';
const imageB64   = body.image     ?? null;
const mediaType  = body.mediaType ?? 'image/jpeg';
const history    = body.history   ?? [];

// Rebuild history as Anthropic messages
const messages = history.map(h => ({
  role: h.role === 'assistant' ? 'assistant' : 'user',
  content: h.text ?? ''
}));

// Build current user turn content
const userContent = [];

if (imageB64) {
  userContent.push({
    type: 'image',
    source: {
      type: 'base64',
      media_type: mediaType,
      data: imageB64
    }
  });
}

const textToSend = userText || 'Проанализируй это изображение урожая и определи его состояние здоровья.';
userContent.push({ type: 'text', text: textToSend });

messages.push({ role: 'user', content: userContent });

return [{
  json: {
    anthropicBody: {
      model: 'claude-opus-4-7',
      max_tokens: 1500,
      system: `Ты опытный агроном и специалист по защите растений с 20-летним стажем. Помогаешь фермерам Казахстана.\n\nПри анализе фотографии урожая:\n1. Определи культуру (пшеница, подсолнечник, кукуруза и т.д.) если видно\n2. Оцени общее состояние: ЗДОРОВОЕ / ПОД УГРОЗОЙ / БОЛЬНОЕ\n3. Выяви признаки болезней, вредителей или дефицитов питательных веществ\n4. Дай прогноз развития ситуации без вмешательства\n5. Предложи конкретные меры лечения или профилактики\n\nОтвечай структурированно, на русском языке. Будь конкретен и практичен.`,
      messages
    }
  }
}];

// Extract text from Anthropic response
const resp = $input.first().json;

let text = '';
if (resp.content && Array.isArray(resp.content)) {
  text = resp.content
    .filter(c => c.type === 'text')
    .map(c => c.text)
    .join('\n');
} else if (resp.error) {
  text = `Ошибка API: ${resp.error.message ?? JSON.stringify(resp.error)}`;
} else {
  text = JSON.stringify(resp, null, 2);
}

return [{ json: { response: text } }];
